using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Get strongly-typed metadata: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");
Console.WriteLine($"  Kind = {personInfo.Kind}");
Console.WriteLine($"  Properties: {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");

// 2) Probe without throwing: TryGetTypeInfo returns false if unavailable
//    Here we try a type that IS available (int):
if (options.TryGetTypeInfo(typeof(int), out JsonTypeInfo? intInfo))
{
    Console.WriteLine($"\nProbe succeeded for: {intInfo!.Type.Name}");
}

//    Now simulate a case where metadata is NOT available —
//    use a resolver that only handles Person, nothing else:
var limitedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new LimitedResolver()
};

if (limitedOptions.TryGetTypeInfo(typeof(Person), out _))
    Console.WriteLine("\nLimitedResolver: Person metadata IS available");

if (!limitedOptions.TryGetTypeInfo(typeof(int), out _))
    Console.WriteLine("LimitedResolver: int metadata is NOT available (no exception thrown)");

// --- Types ---

public record Person(string Name, int Age);

// A custom resolver that only resolves Person
file class LimitedResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(Person))
            return _inner.GetTypeInfo(type, options);
        return null; // signal "not available"
    }
}

